SELECT * FROM gra_project.meteor_data
WHERE user_id = #{userId}
ORDER BY datetime DESC
LIMIT #{limit}

SELECT * FROM gra_project.meteor_data
WHERE user_id = #{userId} AND element_code = #{elementCode}
ORDER BY datetime DESC
LIMIT #{limit}

SELECT date_trunc(#{granularity}, datetime) AS bucket,
       AVG(value) AS avg_value,
       MIN(value) AS min_value,
       MAX(value) AS max_value
FROM gra_project.meteor_data
WHERE user_id = #{userId}
  AND element_code = #{elementCode}
  AND datetime BETWEEN #{startTime} AND #{endTime}

      AND CAST(station_id AS INTEGER) = ANY(
          ARRAY[

              #{sid}

          ]::integer[]
      )


      AND task_id = ANY(
          ARRAY[

              #{tid}

          ]::bigint[]
      )

GROUP BY bucket
ORDER BY bucket

SELECT DISTINCT element_code FROM gra_project.meteor_data
WHERE user_id = #{userId}
ORDER BY element_code

SELECT DISTINCT station_id FROM gra_project.meteor_data
WHERE user_id = #{userId}
ORDER BY station_id

SELECT station_id AS "stationId", AVG(value) AS "avgValue"
FROM gra_project.meteor_data
WHERE user_id = #{userId}
  AND element_code = #{elementCode}
  AND datetime BETWEEN #{startTime} AND #{endTime}
GROUP BY station_id

SELECT m.station_id,
       ws.station_name,
       ws.province,
       ws.latitude,
       ws.longitude,
       AVG(m.value) AS avg_value
FROM gra_project.meteor_data m
JOIN gra_project.weather_stations ws ON CAST(m.station_id AS VARCHAR) = ws.station_id
WHERE m.user_id = #{userId}
  AND m.element_code = #{elementCode}
  AND m.datetime BETWEEN #{startTime} AND #{endTime}

      AND ws.province = #{province}

GROUP BY m.station_id, ws.station_name, ws.province, ws.latitude, ws.longitude

SELECT element_code,
       date_trunc(#{granularity}, datetime) AS bucket,
       AVG(value) AS avg_value
FROM gra_project.meteor_data
WHERE user_id = #{userId}
  AND element_code = ANY(
      ARRAY[

          #{code}

      ]::varchar[]
  )

      AND CAST(station_id AS INTEGER) = ANY(
          ARRAY[

              #{sid}

          ]::integer[]
      )


      AND task_id = ANY(
          ARRAY[

              #{tid}

          ]::bigint[]
      )

  AND datetime BETWEEN #{startTime} AND #{endTime}
GROUP BY element_code, bucket
ORDER BY bucket ASC, element_code ASC

SELECT * FROM gra_project.meteor_data
WHERE user_id = #{userId}
  AND element_code = #{elementCode}
  AND datetime BETWEEN #{startTime} AND #{endTime}
ORDER BY datetime ASC

SELECT * FROM gra_project.meteor_data
WHERE user_id = #{userId}
  AND element_code = #{elementCode}
  AND datetime BETWEEN #{startTime} AND #{endTime}

                    AND CAST(station_id AS INTEGER) = #{stationId}

ORDER BY datetime ASC

